// ============================================
// 辅助函数
// ============================================

/**
 * 获取指定阶段的特征描述
 */
export function getStageCharacteristics(stage: number): StageCharacteristics | undefined {
  return stageCharacteristics[stage];
}

/**
 * 获取指定阶段和场景类型的服装配置
 * 使用向下兼容策略：找不到精确匹配时返回最接近的低阶段配置
 */
export function getClothingByStage(stage: number, sceneType: '公共' | '私密'): ClothingSet {
  // 可用的服装阶段点
  const availableStages = [20, 15, 10, 5, 1];

  // 查找适配的服装等级（向下兼容）
  const clothingStage = availableStages.find(s => stage >= s) ?? 1;

  return clothingByStageAndScene[clothingStage]?.[sceneType] ?? clothingByStageAndScene[1]['公共'];
}

